const makeErrorResponse = (options: {
  readonly status: number;
  readonly code: string;
  readonly message: string;
}): HttpServerResponse.HttpServerResponse =>
  HttpServerResponse.jsonUnsafe(
    {
      error: {
        code: options.code,
